package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testGetIgnoreEmptyLines_Default() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertTrue(format.getIgnoreEmptyLines());
    }

    @Test
    void testGetIgnoreEmptyLines_WithIgnoreEmptyLinesTrue() {
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreEmptyLines(true);
        assertTrue(format.getIgnoreEmptyLines());
    }

    @Test
    void testGetIgnoreEmptyLines_WithIgnoreEmptyLinesFalse() {
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreEmptyLines(false);
        assertFalse(format.getIgnoreEmptyLines());
    }

    @Test
    void testGetIgnoreEmptyLines_ExcelFormat() {
        CSVFormat format = CSVFormat.EXCEL;
        assertFalse(format.getIgnoreEmptyLines());
    }

    @Test
    void testGetIgnoreEmptyLines_MySQLFormat() {
        CSVFormat format = CSVFormat.MYSQL;
        assertFalse(format.getIgnoreEmptyLines());
    }

    @Test
    void testGetIgnoreEmptyLines_PostgreSQLCSVFormat() {
        CSVFormat format = CSVFormat.POSTGRESQL_CSV;
        assertFalse(format.getIgnoreEmptyLines());
    }

    @Test
    void testGetIgnoreEmptyLines_PostgreSQLTextFormat() {
        CSVFormat format = CSVFormat.POSTGRESQL_TEXT;
        assertFalse(format.getIgnoreEmptyLines());
    }

    @Test
    void testGetIgnoreEmptyLines_RFC4180Format() {
        CSVFormat format = CSVFormat.RFC4180;
        assertFalse(format.getIgnoreEmptyLines());
    }

    @Test
    void testGetIgnoreEmptyLines_TDFFormat() {
        CSVFormat format = CSVFormat.TDF;
        assertTrue(format.getIgnoreEmptyLines());
    }
}
